- (void)checkBLECreateKeyButton {
    BOOL showCreateKeyFlag = NO;
    BOOL bleKeyExist = NO;
    if ([CTMediator isSDK2ndCar]) {
        bleKeyExist = [self isBLECardValid];
        if (bleKeyExist || [CTMediator isMona]) {
            showCreateKeyFlag = NO;
        } else {
            showCreateKeyFlag = YES;
        }
    } else {
        bleKeyExist = [XPBLEKeyManager.instance isSafeKeyOrCertKeyExisted];
        if(!CTMediator.hasBleAbility || bleKeyExist){
            showCreateKeyFlag = NO;
        }else{
            showCreateKeyFlag = YES;
        }
    }
    [self configShowCreateKeyButton:showCreateKeyFlag && XPVehicleSDK.currentAbilityConfig.bleKeyVersion != BleKeyProtocolVesionV3];

